INSERT INTO `recipe_instructions` VALUES (1,'REC001',1,'Saut├⌐ ginger and garlic until fragrant.'),(2,'REC001',2,'Add chicken and cook until slightly browned.'),(3,'REC001',3,'Stir in rice and water, bring to a boil.'),(4,'REC001',4,'Simmer until rice is tender and porridge consistency is reached.'),(5,'REC002',1,'Boil macaroni until al dente.'),(6,'REC002',2,'In a separate pot, saut├⌐ onions and shredded chicken.'),(7,'REC002',3,'Add broth and vegetables, simmer until tender.'),(8,'REC002',4,'Stir in milk and cooked macaroni, season to taste.'),(9,'REC003',1,'Saut├⌐ garlic and pork until fat is rendered.'),(10,'REC003',2,'Add soy sauce and vinegar, do not stir immediately.'),(11,'REC003',3,'Add string beans and water.'),(12,'REC003',4,'Cook until beans are tender yet still slightly crisp.'),(13,'REC004',1,'Cook spaghetti according to package instructions.'),(14,'REC004',2,'Saut├⌐ meat and hotdogs until browned.'),(15,'REC004',3,'Pour in tomato sauce and simmer for 15 minutes.'),(16,'REC004',4,'Toss with pasta and top with grated cheese.'),(17,'REC005',1,'Bring chicken broth to a gentle simmer.'),(18,'REC005',2,'Slowly drizzle beaten eggs while stirring in one direction.'),(19,'REC005',3,'Thicken with cornstarch slurry.'),(20,'REC005',4,'Garnish with sliced green onions.'),(21,'REC006',1,'Heat oil in a pan.'),(22,'REC006',2,'Add brown sugar and wait for it to float/caramelize.'),(23,'REC006',3,'Add bananas and coat them with the melted sugar.'),(24,'REC006',4,'Drain and serve on skewers.'),(25,'REC007',1,'Boil mung beans until soft and skins burst.'),(26,'REC007',2,'Saut├⌐ garlic, onions, and tomatoes with pork.'),(27,'REC007',3,'Pour in cooked mung beans.'),(28,'REC007',4,'Add spinach at the very end and season.'),(29,'REC008',1,'Boil beef until very tender.'),(30,'REC008',2,'Saut├⌐ aromatics and add beef with soy sauce and star anise.'),(31,'REC008',3,'Thicken the sauce slightly.'),(32,'REC008',4,'Serve with hot garlic fried rice and clear soup.');
/*!40000 ALTER TABLE `recipe_instructions` ENABLE KEYS */;
